const AnimatedLogo = ({ size = 260, className = '' }: AnimatedLogoProps) => {
  const ref = useRef<HTMLDivElement>(null);
  const isInView = useInView(ref, { once: true, margin: '-40px' });

  return (
    <div
      ref={ref}
      className={`relative inline-block select-none ${className}`}
      style={{ width: size, height: size }}
    >
      {/* Ambient radial glow — pulses behind the logo */}
      <motion.div
        className="absolute inset-[-20%] rounded-full pointer-events-none"
        style={{
          background:
            'radial-gradient(circle, rgba(217,185,90,0.18) 0%, rgba(139,92,246,0.10) 45%, transparent 70%)',
        }}
        animate={{ scale: [1, 1.12, 1], opacity: [0.5, 0.9, 0.5] }}
        transition={{ duration: 4, repeat: Infinity, ease: 'easeInOut' }}
      />

      {/* Floating + slight rotation wrapper */}
      <motion.div
        animate={{ y: [0, -12, 0], rotate: [-0.8, 0.8, -0.8] }}
        transition={{ duration: 5.5, repeat: Infinity, ease: 'easeInOut' }}
        style={{ width: size, height: size, position: 'relative' }}
      >
        <svg
          xmlns="http://www.w3.org/2000/svg"
          viewBox="0 0 512 512"
          width={size}
          height={size}
          style={{ overflow: 'visible' }}
        >
          <defs>
            {/* Shimmer sweep gradient — moves left to right */}
            <linearGradient id="shimmerGrad" x1="0%" y1="0%" x2="100%" y2="0%">
              <stop offset="0%" stopColor="#D9B95A" stopOpacity="0" />
              <stop offset="40%" stopColor="#ffffff" stopOpacity="0.25" />
              <stop offset="55%" stopColor="#a78bfa" stopOpacity="0.35" />
              <stop offset="100%" stopColor="#fbbf24" stopOpacity="0" />
            </linearGradient>

            {/* Clip path so shimmer stays inside the logo shape */}
            <clipPath id="logoClip">
              {PATHS.map((p, i) => (
                <path key={i} d={p.d} />
              ))}
            </clipPath>

            {/* Drop shadow filter */}
            <filter id="logoGlow" x="-20%" y="-20%" width="140%" height="140%">
              <feGaussianBlur stdDeviation="8" result="blur" />
              <feFlood floodColor="#D9B95A" floodOpacity="0.3" result="color" />
              <feComposite
                in="color"
                in2="blur"
                operator="in"
                result="shadow"
              />
              <feMerge>
                <feMergeNode in="shadow" />
                <feMergeNode in="SourceGraphic" />
              </feMerge>
            </filter>
          </defs>

          {/* ── Layer 1: base filled paths (staggered fade-in) ── */}
          <g filter="url(#logoGlow)">
            {PATHS.map((p, i) => (
              <motion.path
                key={i}
                d={p.d}
                fill="#D9B95A"
                initial={{ opacity: 0, scale: 0.92 }}
                animate={
                  isInView
                    ? { opacity: 1, scale: 1 }
                    : { opacity: 0, scale: 0.92 }
                }
                transition={{
                  opacity: { duration: 0.5, delay: p.delay, ease: 'easeOut' },
                  scale: {
                    duration: 0.6,
                    delay: p.delay,
                    ease: [0.34, 1.56, 0.64, 1],
                  },
                }}
                style={{ transformOrigin: 'center' }}
              />
            ))}
          </g>

          {/* ── Layer 2: electricity pulse — each path brightens independently ── */}
          {PATHS.map((p, i) => (
            <motion.path
              key={`pulse-${i}`}
              d={p.d}
              fill="#ffffff"
              initial={{ opacity: 0 }}
              animate={
                isInView
                  ? {
                      opacity: [0, 0, 0.35, 0.6, 0.2, 0],
                    }
                  : { opacity: 0 }
              }
              transition={{
                duration: p.pulseDuration,
                delay: p.pulseDelay + 1.2,
                repeat: Infinity,
                repeatDelay: p.pulseDuration * 1.5,
                ease: 'easeInOut',
              }}
            />
          ))}

          {/* ── Layer 3: shimmer sweep (clipped to logo shape) ── */}
          <g clipPath="url(#logoClip)">
            <motion.rect
              x="-512"
              y="0"
              width="512"
              height="512"
              fill="url(#shimmerGrad)"
              initial={{ x: -512 }}
              animate={isInView ? { x: ['-512', '512'] } : { x: '-512' }}
              transition={{
                duration: 1.8,
                delay: 1.0,
                repeat: Infinity,
                repeatDelay: 3.5,
                ease: [0.4, 0, 0.6, 1],
              }}
            />
          </g>

          {/* ── Layer 4: violet accent glow on the chip side (right half) ── */}
          <motion.rect
            x="260"
            y="100"
            width="260"
            height="320"
            fill="url(#shimmerGrad)"
            opacity={0}
            clipPath="url(#logoClip)"
            animate={
              isInView
                ? {
                    opacity: [0, 0.4, 0],
                    x: [260, 280, 260],
                  }
                : { opacity: 0 }
            }
            transition={{
              duration: 2.5,
              delay: 2.8,
              repeat: Infinity,
              repeatDelay: 4,
              ease: 'easeInOut',
            }}
          />
        </svg>
      </motion.div>
    </div>
  );
};

export default AnimatedLogo;
